// ============================================
// Verifica si estamos en horario laboral
// Zona horaria: America/Montevideo (UTC-3)
// Horario permitido: 10:00 - 19:00 L-V
// ============================================

const now = new Date();

// Convertir a hora de Uruguay (UTC-3)
const utcHour = now.getUTCHours();
const uyHour = (utcHour - 3 + 24) % 24;
const dayOfWeek = now.getUTCDay(); // 0=Dom, 6=Sab

// Horario laboral: 10:00 a 19:00, Lunes a Viernes
const isBusinessHours = uyHour >= 10 && uyHour < 19 && dayOfWeek >= 1 && dayOfWeek <= 5;

return [{
  json: {
    isBusinessHours,
    horaUY: uyHour,
    diaSemana: dayOfWeek,
    timestamp: now.toISOString()
  }
}];

