SELECT
  COALESCE(
    (SELECT cantidad FROM envios_diarios WHERE fecha = CURRENT_DATE),
    0
  ) AS enviados_hoy,
  COALESCE(
    (SELECT value::int FROM config WHERE key = 'max_envios_dia'),
    30
  ) AS max_dia;

