// ============================================
// Personaliza el mensaje según el rubro del comercio
// Usa español rioplatense (Uruguay)
// ============================================

const lead = $json;
const nombre = lead.nombre;
const rubro = (lead.rubro || 'comercio').toLowerCase();
const ciudad = lead.ciudad || '';

// Templates por categoría de rubro
const templates = {
  gastronomia: [
    `Hola! 👋 Vi que tienen ${nombre} en ${ciudad}. ¿Manejan muchas consultas por WhatsApp sobre el menú, reservas o delivery?\n\nEstamos ayudando a locales gastronómicos a responder automáticamente y no perder clientes cuando no pueden contestar al momento.\n\n¿Les copa saber más? Sin compromiso 🙌`,
    `Buenas! Vi ${nombre} en ${ciudad} y me pareció re interesante. Estamos trabajando con restaurantes de la zona para automatizar pedidos y reservas por WhatsApp.\n\n¿Tienen 2 minutos para que les cuente? 😊`
  ],
  estetica: [
    `Hola! 👋 Vi que tienen ${nombre} en ${ciudad}. Estamos ayudando a centros de estética y peluquerías a automatizar la agenda de turnos y las consultas por WhatsApp, para que no pierdan reservas.\n\n¿Tienen 2 minutos para que les cuente cómo funciona? Sin compromiso 😊`,
    `Buenas! Vi ${nombre} y quería contactarlos. Muchas peluquerías y centros de estética nos cuentan que pierden turnos porque no llegan a responder WhatsApp a tiempo.\n\nEstamos ayudando a resolver eso con automatizaciones simples. ¿Les interesa saber más? 🙌`
  ],
  salud: [
    `Hola! 👋 Vi que tienen ${nombre} en ${ciudad}. Estamos ayudando a consultorios y clínicas a gestionar turnos y consultas de pacientes de forma automática por WhatsApp.\n\n¿Les interesa saber cómo funciona? Sin compromiso 🙌`,
    `Buenas! Vi ${nombre} y me pareció que podríamos ayudarlos. Muchos consultorios nos dicen que pierden pacientes porque no llegan a responder a tiempo.\n\nTenemos algo que puede servir. ¿2 minutos para contarles? 😊`
  ],
  servicios: [
    `Hola! 👋 Vi ${nombre} en ${ciudad} y quería contactarlos. Estamos ayudando a negocios de servicios a automatizar la atención al cliente y agendar citas sin esfuerzo.\n\n¿Les copa una charla rápida de 2 min para ver si les sirve? Sin compromiso 🙌`,
    `Buenas! Vi que tienen ${nombre} y me pareció interesante contactarlos. Estamos ayudando a negocios como el suyo a no perder consultas y automatizar lo repetitivo.\n\n¿Tienen un minutito? 😊`
  ],
  generico: [
    `Hola! 👋 Vi el negocio de ustedes en ${ciudad} y me pareció interesante contactarlos.\n\nEstamos ayudando a comercios de ${rubro} a automatizar tareas del día a día (responder consultas, agendar, gestionar pedidos) para ganar tiempo y no perder clientes.\n\n¿Les copa saber un poco más? Sin compromiso 🙌`,
    `Buenas! Vi ${nombre} y quería escribirles. Trabajamos ayudando a negocios a atender mejor a sus clientes con automatizaciones simples por WhatsApp.\n\n¿Tienen 2 minutos para una charla rápida? Sin compromiso 😊`
  ]
};

// Clasificar rubro en categoría
let categoria = 'generico';
const rubroLower = rubro.toLowerCase();

if (['restaurante', 'panadería', 'cafetería', 'bar', 'pizzería', 'delivery', 'food'].some(r => rubroLower.includes(r))) {
  categoria = 'gastronomia';
} else if (['peluquería', 'barbería', 'estética', 'spa', 'belleza', 'uñas', 'masaje'].some(r => rubroLower.includes(r))) {
  categoria = 'estetica';
} else if (['clínica', 'consultorio', 'dental', 'médico', 'veterinaria', 'óptica', 'salud'].some(r => rubroLower.includes(r))) {
  categoria = 'salud';
} else if (['estudio', 'inmobiliaria', 'taller', 'academia', 'gimnasio', 'hotel', 'lavadero'].some(r => rubroLower.includes(r))) {
  categoria = 'servicios';
}

// Seleccionar template aleatorio de la categoría
const templatesList = templates[categoria];
const mensaje = templatesList[Math.floor(Math.random() * templatesList.length)];

return {
  json: {
    ...lead,
    mensaje,
    categoriaRubro: categoria
  }
};
